import*as Instance from"../lib/instance.js";import*as Schema from"../lib/schema.js";import{getKeywordName}from"../lib/keywords.js";const id="https://json-schema.org/keyword/draft-04/maximum",compile=async(e,t,r)=>{var a=getKeywordName(e.dialectId,"https://json-schema.org/keyword/draft-04/exclusiveMaximum"),a=await Schema.step(a,r),r=Schema.value(a);return[Schema.value(e),r]},interpret=([e,t],r)=>{if(!Instance.typeOf(r,"number"))return!0;r=Instance.value(r);return t?r<e:r<=e};export default{id:id,compile:compile,interpret:interpret};